# Tool call validation: schema enforcement
from typing import Any
import json, jsonschema

class ToolValidator:
    """
    Validates LLM-generated tool calls against JSON Schema.
    Catches missing params, wrong types, and hallucinated argument values.
    """
    def __init__(self):
        self.schemas: dict[str, dict] = {}

    def register_tool(self, name: str, parameters: dict):
        """Register a tool's JSON Schema."""
        self.schemas[name] = {
            "type": "object",
            "properties": parameters.get("properties", {}),
            "required": parameters.get("required", [])
        }

    def validate(self, tool_name: str, arguments: dict) -> tuple[bool, str]:
        """Validate a tool call. Returns (is_valid, error_message)."""
        if tool_name not in self.schemas:
            return False, f"Unknown tool: {tool_name}"
        try:
            jsonschema.validate(instance=arguments, schema=self.schemas[tool_name])
            return True, ""
        except jsonschema.ValidationError as e:
            return False, f"Validation error: {e.message}"

    def extract_tool_call(self, model_output: str) -> list[dict]:
        """
        Extract tool calls from model output.
        Handles multiple formats: OpenAI, Claude, Gemini.
        """
        tool_calls = []
        # Try OpenAI format: {"function": "name", "arguments": {...}}
        # Try function calling format: {"name": "...", "arguments": {...}}
        # Try code block format: ```tool_call\n{"name":...}\n```
        for pattern in [self._parse_openai_format, self._parse_anthropic_format,
                        self._parse_code_block]:
            calls = pattern(model_output)
            if calls:
                tool_calls.extend(calls)
                break
        return tool_calls

    def _parse_openai_format(self, text: str) -> list[dict]:
        calls = []
        for line in text.split("\n"):
            if '"function"' in line or '"name"' in line:
                try:
                    obj = json.loads(line.strip().rstrip(","))
                    calls.append({
                        "name": obj.get("function", obj.get("name")),
                        "arguments": obj.get("arguments", {})
                    })
                except json.JSONDecodeError:
                    pass
        return calls

    def _parse_anthropic_format(self, text: str) -> list[dict]:
        # Anthropic's tool_use blocks: <function_calls>...<invoke name="...">
        # Simplified: look for JSON in XML tags
        import re
        matches = re.findall(r'<invoke name="(\w+)">\s*<parameter>(.*?)</parameter>', text, re.DOTALL)
        return [{"name": m[0], "arguments": json.loads(m[1])} for m in matches]

    def _parse_code_block(self, text: str) -> list[dict]:
        import re
        matches = re.findall(r'```(?:json)?\s*([\s\S]*?)```', text)
        for match in matches:
            try:
                obj = json.loads(match.strip())
                if isinstance(obj, dict) and "name" in obj:
                    return [obj]
                if isinstance(obj, list):
                    return [o for o in obj if isinstance(o, dict) and "name" in o]
            except json.JSONDecodeError:
                pass
        return []

