# === Schema performance benchmark ===
def benchmark_schema_clarity():
    """
    Staff insight: The cost of a bad schema is not just errors.
    Each retry adds ~500ms + ~500 tokens.
    At 1M tool calls/day, improving accuracy from 85% to 95%
    saves 100K retries/day = ~$200/day in LLM costs.
    """
    calls_per_day = 1_000_000
    accuracy_good = 0.95  # clear schemas
    accuracy_bad = 0.85   # vague schemas

    retries_good = calls_per_day * (1 - accuracy_good)
    retries_bad = calls_per_day * (1 - accuracy_bad)
    extra_cost = (retries_bad - retries_good) * 0.002  # $0.002 per retry
    print(f"Good schemas: {retries_good:.0f} retries/day")
    print(f"Bad schemas:  {retries_bad:.0f} retries/day")
    print(f"Extra cost:   ${extra_cost:.0f}/day = ${extra_cost*365:.0f}/year")

benchmark_schema_clarity()

# Parallel tool dispatch with dependency resolution
from typing import Any
import asyncio, json

class ParallelToolDispatcher:
    """
    Dispatches tool calls in parallel when possible.
    Detects dependencies by analyzing parameter names.
    """
    def __init__(self, tool_runtime):
        self.runtime = tool_runtime

    async def dispatch(self, tool_calls: list[dict]) -> list[dict]:
        """
        Given a list of tool calls, dispatch them efficiently.
        Returns list of {name, arguments, result} dicts.
        """
        results = []

        # Phase 1: identify independent calls (dispatch in parallel)
        independent = []
        for call in tool_calls:
            if self._is_independent(call, tool_calls):
                independent.append(call)

        if independent:
            parallel_results = await asyncio.gather(*[
                self.runtime.call(c["name"], c.get("arguments", {}))
                for c in independent
            ], return_exceptions=True)

            for call, result in zip(independent, parallel_results):
                results.append({
                    "name": call["name"],
                    "arguments": call.get("arguments", {}),
                    "result": str(result) if not isinstance(result, Exception) else f"Error: {result}"
                })

        # Phase 2: dependent calls (dispatch sequentially)
        dependent = [c for c in tool_calls if c not in independent]
        for call in dependent:
            # Resolve references to previous results
            resolved_args = self._resolve_references(
                call.get("arguments", {}), results
            )
            result = await self.runtime.call(call["name"], resolved_args)
            results.append({
                "name": call["name"],
                "arguments": resolved_args,
                "result": str(result)
            })

        return results

    def _is_independent(self, call: dict, all_calls: list[dict]) -> bool:
        """
        A tool call is independent if none of its arguments
        reference results from other tools.
        References look like: "${tool_name.result}" or "${tool_name.field}"
        """
        args_str = json.dumps(call.get("arguments", {}))
        for other in all_calls:
            if other["name"] != call["name"]:
                if f"${{{other['name']}" in args_str:
                    return False
        return True

    def _resolve_references(self, args: dict, results: list[dict]) -> dict:
        """Replace ${tool.field} references with actual results."""
        import re
        args_str = json.dumps(args)

        def replacer(match):
            ref = match.group(1)
            # ref format: "tool_name" or "tool_name.field"
            parts = ref.split(".")
            tool_name = parts[0]
            field = parts[1] if len(parts) > 1 else "result"

            for r in results:
                if r["name"] == tool_name:
                    result_data = r["result"]
                    if isinstance(result_data, dict) and field in result_data:
                        return str(result_data[field])
                    return result_data
            return match.group(0)  # unresolved, leave as-is

        resolved = re.sub(r'\${([^}]+)}', replacer, args_str)
        return json.loads(resolved)


# === Dependency graph for complex chains ===
from collections import defaultdict, deque

class ToolDependencyGraph:
    """
    Builds a dependency DAG for tool calls and executes in topological order.
    """
    def __init__(self, tool_calls: list[dict]):
        self.calls = tool_calls
        self.graph = defaultdict(set)
        self._build()

    def _build(self):
        names = [c["name"] for c in self.calls]
        for i, call in enumerate(self.calls):
            args_str = json.dumps(call.get("arguments", {}))
            for j, other_name in enumerate(names):
                if i != j and f"${{{other_name}" in args_str:
                    self.graph[call["name"]].add(other_name)

    def execution_order(self) -> list[list[str]]:
        """Returns batches of tools that can run in parallel."""
        in_degree = {c["name"]: 0 for c in self.calls}
        for deps in self.graph.values():
            for dep in deps:
                if dep in in_degree:
                    in_degree[dep] = in_degree.get(dep, 0) + 1

        queue = deque([name for name, deg in in_degree.items() if deg == 0])
        batches = []

        while queue:
            batch = list(queue)
            batches.append(batch)
            for name in batch:
                for dependent in self.graph:
                    if name in self.graph[dependent]:
                        in_degree[dependent] -= 1
                        if in_degree[dependent] == 0:
                            queue.append(dependent)
                queue.popleft()

        return batches

# Tool use observability and cost tracking
from dataclasses import dataclass, field
import time, json
from collections import defaultdict

@dataclass
class ToolCallRecord:
    tool_name: str
    arguments: dict
    duration_ms: float
    success: bool
    error: str
    user_id: str
    session_id: str
    model_name: str
    timestamp: float = field(default_factory=time.time)


class ToolObservability:
    """
    Collects and exports tool call metrics.
    """
    def __init__(self):
        self.records: list[ToolCallRecord] = []
        self.metrics: dict[str, dict] = {}

    def record(self, call: ToolCallRecord):
        self.records.append(call)
        # Update running metrics
        if call.tool_name not in self.metrics:
            self.metrics[call.tool_name] = {
                "count": 0, "errors": 0, "total_latency_ms": 0
            }
        m = self.metrics[call.tool_name]
        m["count"] += 1
        m["total_latency_ms"] += call.duration_ms
        if not call.success:
            m["errors"] += 1

    def get_snapshot(self) -> dict:
        """Return current metrics for dashboard."""
        snapshot = {}
        for tool_name, m in self.metrics.items():
            avg_latency = m["total_latency_ms"] / max(m["count"], 1)
            snapshot[tool_name] = {
                "call_count": m["count"],
                "error_rate": round(m["errors"] / max(m["count"], 1), 3),
                "avg_latency_ms": round(avg_latency, 1),
            }
        return snapshot

    def cost_report(self, cost_per_call: dict[str, float]) -> dict:
        """Estimate cost per tool."""
        report = {}
        for tool_name, m in self.metrics.items():
            cost_per = cost_per_call.get(tool_name, 0.001)  # default $0.001/call
            report[tool_name] = {
                "calls": m["count"],
                "cost_per_call": cost_per,
                "total_cost": round(m["count"] * cost_per, 4)
            }
        return report


# === Tool result cache ===
class ToolCache:
    """
    Caches tool results with TTL.
    Only for idempotent (read-only) tools.
    """
    def __init__(self, default_ttl: float = 300.0):
        self.cache: dict[str, tuple[Any, float]] = {}  # key -> (value, expiry)
        self.default_ttl = default_ttl
        self.hits = 0
        self.misses = 0

    def _make_key(self, tool_name: str, arguments: dict) -> str:
        return f"{tool_name}:{hash(json.dumps(arguments, sort_keys=True))}"

    def get(self, tool_name: str, arguments: dict) -> Any | None:
        key = self._make_key(tool_name, arguments)
        if key in self.cache:
            value, expiry = self.cache[key]
            if time.time() < expiry:
                self.hits += 1
                return value
            del self.cache[key]
        self.misses += 1
        return None

    def set(self, tool_name: str, arguments: dict, value: Any, ttl: float = None):
        key = self._make_key(tool_name, arguments)
        self.cache[key] = (value, time.time() + (ttl or self.default_ttl))

    def hit_rate(self) -> float:
        total = self.hits + self.misses
        return self.hits / max(total, 1)

    def invalidate(self, tool_name: str):
        """Invalidate all cache entries for a tool (e.g., after data update)."""
        self.cache = {k: v for k, v in self.cache.items() if not k.startswith(f"{tool_name}:")}


# FAANG Staff Insight:
# Cache hit rate should be monitored and optimized.
# Low hit rate (<20%) = caching wrong tools or wrong TTLs.
# High hit rate (>80%) with stale data = TTL too long.
# Target: 40-60% hit rate for a well-balanced cache.
